pageProps.style:
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0;}
:root{--bg-page:#F7F4EC;--surface:#FFFFFF;--surface-muted:#F6E9D8;--border:#E3D8C8;--text-primary:#2A2118;--text-secondary:#6F6556;--accent:#C4722A;--accent-soft:#F8E0CB;--accent-muted:#E8C6A1;--success:#2A7A6A;--success-soft:#D6EEE9;--error:#A32D2D;--error-soft:#FBE7E7;--radius:18px;--radius-sm:12px;--tap:48px;}
html{-webkit-text-size-adjust:100%;}
body{font-family:'DM Sans',sans-serif;background:var(--bg-page);color:var(--text-primary);min-height:100vh;display:flex;flex-direction:column;align-items:center;padding:0 0 80px 0;overflow-x:hidden;width:100%;}
.hidden{display:none!important;}
.site-header{width:100%;background:var(--surface);border-bottom:1.5px solid var(--border);position:sticky;top:0;z-index:50;box-shadow:0 18px 35px rgba(0,0,0,0.06);}
.header-inner{max-width:1080px;margin:0 auto;display:flex;align-items:center;justify-content:space-between;padding:16px 18px;flex-wrap:wrap;gap:16px;}
.brand{display:flex;align-items:center;gap:10px;text-decoration:none;}
.brand-icon{font-size:1.65rem;}
.brand-name{font-family:'Fraunces',serif;font-size:1.25rem;font-weight:700;color:var(--text-primary);}
.main-nav{display:flex;gap:20px;flex-wrap:wrap;align-items:center;}
.nav-link{font-family:'DM Sans',sans-serif;font-size:0.96rem;font-weight:500;color:var(--text-secondary);text-decoration:none;transition:color 0.2s;}
.nav-link:hover,.nav-link.active{color:var(--accent);}
.layout-wrapper{max-width:1080px;width:100%;margin:0 auto 0;padding:0 16px;display:grid;grid-template-columns:minmax(0,1fr) 300px;gap:40px;align-items:start;box-sizing:border-box;min-width:0;}
.main-content{display:flex;flex-direction:column;align-items:center;width:100%;min-width:0;}
.sidebar{width:100%;min-width:0;display:flex;justify-content:center;}
.calc-header{text-align:center;margin-bottom:36px;width:100%;max-width:560px;}
.calc-title{font-family:'Fraunces',serif;font-size:clamp(1.45rem,4.5vw,3.2rem);font-weight:700;line-height:1.15;letter-spacing:-0.02em;color:var(--text-primary);text-wrap:balance;word-break:break-word;}
.subtitle{margin-top:10px;font-size:clamp(0.88rem,2.5vw,1rem);color:var(--text-secondary);line-height:1.6;max-width:480px;margin-left:auto;margin-right:auto;}
.ad-placeholder{background:var(--surface);border:1.5px dashed var(--border);border-radius:var(--radius-sm);display:flex;flex-direction:column;align-items:center;justify-content:center;gap:6px;text-align:center;padding:22px 14px;}
.ad-placeholder .ad-label{font-size:0.72rem;font-weight:600;letter-spacing:.14em;text-transform:uppercase;color:var(--text-secondary);}
.ad-placeholder .ad-size{font-size:0.82rem;color:var(--text-secondary);}
.ad-right{width:100%;height:600px;position:sticky;top:90px;}
.ad-bottom{width:100%;max-width:728px;height:90px;margin:32px auto;}
.card{background:var(--surface);border:1px solid var(--border);border-radius:var(--radius);padding:clamp(18px,4vw,36px);width:100%;max-width:560px;box-sizing:border-box;box-shadow:0 20px 40px rgba(0,0,0,0.06);}
.toggle-group{display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:24px;}
.toggle-btn{border:1.5px solid var(--border);background:var(--surface);border-radius:var(--radius-sm);min-height:var(--tap);padding:12px 10px;cursor:pointer;font-family:'DM Sans',sans-serif;font-size:clamp(0.95rem,3vw,1rem);font-weight:500;color:var(--text-secondary);transition:all .18s ease;display:flex;align-items:center;justify-content:center;gap:8px;white-space:nowrap;touch-action:manipulation;}
.toggle-btn span.emoji{font-size:1.3rem;}
.toggle-btn:hover{border-color:var(--accent);color:var(--accent);background:var(--accent-soft);}
.toggle-btn.active{background:var(--accent-soft);border-color:var(--accent);color:var(--accent);}
.field{margin-bottom:22px;}
label{display:block;font-size:0.75rem;font-weight:500;letter-spacing:.07em;text-transform:uppercase;color:var(--text-secondary);margin-bottom:10px;}
.size-hint{font-size:0.72rem;color:var(--text-secondary);display:block;font-weight:400;text-transform:none;letter-spacing:0;margin-top:3px;}
.age-row{display:grid;grid-template-columns:1fr 1fr;gap:10px;}
select,input[type="number"]{width:100%;min-height:var(--tap);border:1.5px solid var(--border);border-radius:var(--radius-sm);background:var(--surface);font-family:'DM Sans',sans-serif;font-size:16px;color:var(--text-primary);padding:12px 14px;appearance:none;-webkit-appearance:none;transition:border-color .15s,box-shadow .15s;outline:none;}
select{background-image:url("data:image/svg+xml,%3Csvg width='12' height='8' viewBox='0 0 12 8' fill='none' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M1 1L6 7L11 1' stroke='%237A6E5F' stroke-width='1.5' stroke-linecap='round' stroke-linejoin='round'/%3E%3C/svg%3E");background-repeat:no-repeat;background-position:right 14px center;padding-right:38px;cursor:pointer;}
select:focus,input[type="number"]:focus{border-color:var(--accent);background:var(--surface);box-shadow:0 0 0 4px rgba(196,114,42,0.12);}
.size-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:8px;}
.size-btn{border:1.5px solid var(--border);background:var(--surface);border-radius:var(--radius-sm);min-height:var(--tap);padding:10px 4px;cursor:pointer;font-family:'DM Sans',sans-serif;font-size:clamp(0.72rem,2.3vw,0.84rem);font-weight:500;color:var(--text-secondary);transition:all .15s ease;text-align:center;line-height:1.35;touch-action:manipulation;}
.size-btn .dog-emoji{display:block;margin-bottom:3px;font-size:1.05rem;}
.size-btn:hover{border-color:var(--accent);color:var(--accent);background:var(--accent-soft);}
.size-btn.active{background:var(--accent-soft);border-color:var(--accent);color:var(--accent);}
.calc-btn{width:100%;min-height:var(--tap);background:var(--accent);color:#fff;font-family:'DM Sans',sans-serif;font-size:1rem;font-weight:600;padding:14px 20px;border:none;border-radius:var(--radius-sm);cursor:pointer;transition:background .18s ease,transform .1s ease,box-shadow .18s ease;margin-top:6px;box-shadow:0 14px 30px rgba(196,114,42,0.18);touch-action:manipulation;}
.calc-btn:hover{background:#b35a1e;}
.calc-btn:active{transform:scale(0.98);}
.error-msg{margin-top:12px;background:var(--error-soft);border:1.5px solid var(--error);border-radius:var(--radius-sm);padding:12px 14px;font-size:0.9rem;color:var(--error);display:none;}
.result-card{background:var(--success-soft);border:1.5px solid rgba(42,122,106,0.18);border-radius:var(--radius);padding:0 clamp(16px,5vw,28px);margin-top:0;max-height:0;overflow:hidden;text-align:center;opacity:0;transform:translateY(10px);transition:all .35s ease;}
.result-card.visible{border-width:1.5px;padding:clamp(16px,5vw,28px);margin-top:20px;max-height:400px;opacity:1;transform:translateY(0);}
.result-label{font-size:0.95rem;color:var(--text-secondary);margin-bottom:10px;}
.result-number{font-size:clamp(2rem,6vw,3.5rem);font-weight:700;color:var(--text-primary);line-height:1;}
.result-unit{display:block;margin-top:8px;color:var(--text-secondary);font-weight:500;}
.result-context{margin-top:12px;font-size:0.95rem;color:var(--text-secondary);line-height:1.75;}
.articles-section{width:100%;max-width:680px;margin-top:56px;}
.articles-section-label{font-size:0.72rem;font-weight:600;letter-spacing:.12em;text-transform:uppercase;color:var(--text-secondary);margin-bottom:28px;display:flex;align-items:center;gap:10px;}
.articles-section-label::after{content:'';flex:1;height:1.5px;background:var(--border);}
.article-block{margin-bottom:56px;padding:28px 0;border-bottom:1.5px solid var(--surface-muted);}
.article-block:last-child{border-bottom:none;margin-bottom:0;padding-bottom:0;}
.article-block h2{font-family:'Fraunces',serif;font-size:clamp(1.3rem,4vw,1.6rem);font-weight:700;color:var(--text-primary);margin-bottom:10px;margin-top:0;letter-spacing:-0.01em;line-height:1.2;text-wrap:balance;}
.article-block .article-meta{font-size:0.75rem;color:var(--text-secondary);margin-bottom:18px;padding-bottom:16px;border-bottom:1.5px solid var(--surface-muted);}
.article-block h3{font-family:'DM Sans',sans-serif;font-size:1rem;font-weight:500;color:var(--text-primary);margin-top:24px;margin-bottom:8px;}
.article-block p{font-size:clamp(0.9rem,2.5vw,0.97rem);color:var(--text-secondary);line-height:1.78;margin-bottom:12px;}
.article-block ul{padding-left:20px;margin-bottom:16px;}
.article-block li{font-size:clamp(0.9rem,2.5vw,0.97rem);color:var(--text-secondary);line-height:1.75;margin-bottom:6px;}
.content-wrap{width:100%;max-width:680px;margin-top:56px;padding:0 4px;}
.content-wrap h2{font-family:'Fraunces',serif;font-size:clamp(1.3rem,4vw,1.55rem);font-weight:700;color:var(--text-primary);margin-bottom:12px;margin-top:48px;letter-spacing:-0.01em;text-wrap:balance;}
.content-wrap h3{font-size:1rem;font-weight:500;color:var(--text-primary);margin-top:22px;margin-bottom:6px;}
.content-wrap p{font-size:clamp(0.9rem,2.5vw,0.97rem);color:var(--text-secondary);line-height:1.75;margin-bottom:12px;}
.content-wrap strong{color:var(--text-primary);}
.table-wrap{overflow-x:auto;-webkit-overflow-scrolling:touch;margin:16px 0 24px;border-radius:var(--radius-sm);border:1.5px solid var(--border);background:var(--surface);position:relative;}
.table-scroll-hint{display:none;font-size:0.7rem;color:var(--text-secondary);text-align:right;padding:4px 10px 0;letter-spacing:.03em;}
@media(max-width:540px){.table-scroll-hint{display:block;}}
table{width:100%;border-collapse:collapse;font-size:clamp(0.78rem,2.3vw,0.88rem);background:var(--surface);}
thead tr{background:var(--surface-muted);}
th{padding:10px 14px;text-align:left;white-space:nowrap;font-weight:500;font-size:0.72rem;letter-spacing:.05em;text-transform:uppercase;color:var(--text-secondary);border-bottom:1.5px solid var(--border);}
td{padding:9px 14px;color:var(--text-primary);border-bottom:1px solid var(--surface-muted);white-space:nowrap;}
tr:last-child td{border-bottom:none;}
tbody tr:hover{background:var(--surface-muted);}
img,embed,iframe,video,object{max-width:100%;height:auto;}
.content-wrap ul{padding-left:20px;margin-bottom:16px;}
.content-wrap li{font-size:clamp(0.9rem,2.5vw,0.97rem);color:var(--text-secondary);line-height:1.75;margin-bottom:6px;}
details{border:1.5px solid var(--border);border-radius:var(--radius-sm);margin-bottom:10px;background:var(--surface);overflow:hidden;}
summary{min-height:var(--tap);padding:14px 18px;font-weight:500;font-size:clamp(0.88rem,2.8vw,0.97rem);cursor:pointer;list-style:none;color:var(--text-primary);display:flex;justify-content:space-between;align-items:center;gap:12px;}
summary::-webkit-details-marker{display:none;}
summary::after{content:'+';font-size:1.4rem;color:var(--accent);font-weight:300;flex-shrink:0;transition:transform .2s;}
details[open] summary::after{transform:rotate(45deg);}
.faq-answer{padding:14px 18px 18px;font-size:clamp(0.86rem,2.5vw,0.93rem);color:var(--text-secondary);line-height:1.7;border-top:1px solid var(--surface-muted);}
.divider{border:none;border-top:1.5px solid var(--border);margin:48px auto;width:100%;max-width:680px;}
.site-footer{width:100%;max-width:680px;text-align:center;padding:0 8px 40px;margin:0 auto;}
.footer-nav{display:flex;flex-wrap:wrap;justify-content:center;margin-bottom:20px;border:1.5px solid var(--border);border-radius:var(--radius-sm);overflow:hidden;width:fit-content;margin-left:auto;margin-right:auto;background:var(--surface);}
.footer-link{background:none;border:none;cursor:pointer;font-family:'DM Sans',sans-serif;font-size:0.85rem;font-weight:500;color:var(--text-secondary);padding:10px 16px;min-height:44px;transition:color .15s,background .15s;border-right:1px solid var(--border);}
.footer-link:last-child{border-right:none;}
.footer-link:hover{color:var(--accent);background:var(--accent-soft);}
.footer-sources{font-size:0.75rem;color:var(--text-secondary);line-height:1.65;margin-bottom:16px;}
.footer-sources a{color:var(--accent);text-decoration:none;border-bottom:1px solid var(--accent-soft);}
.footer-copy{font-size:0.72rem;color:var(--text-secondary);}
.modal-backdrop{display:none;position:fixed;inset:0;background:rgba(42,33,24,.25);backdrop-filter:blur(3px);-webkit-backdrop-filter:blur(3px);z-index:100;}
.modal-backdrop.open{display:block;}
.modal{display:none;position:fixed;top:50%;left:50%;transform:translate(-50%,-48%);opacity:0;transition:opacity .22s ease,transform .22s ease;width:min(92vw,560px);max-height:82vh;overflow-y:auto;background:var(--surface);border:1.5px solid var(--border);border-radius:var(--radius);padding:clamp(22px,5vw,36px);z-index:101;}
.modal.open{display:block;opacity:1;transform:translate(-50%,-50%);}
.modal-close{position:absolute;top:14px;right:14px;background:var(--surface);border:1.5px solid var(--border);border-radius:50%;width:36px;height:36px;cursor:pointer;display:flex;align-items:center;justify-content:center;touch-action:manipulation;}
.modal-close:hover{background:var(--accent-soft);color:var(--accent);border-color:var(--accent);}
.modal h2{font-family:'Fraunces',serif;font-size:clamp(1.3rem,4vw,1.6rem);font-weight:700;margin-bottom:14px;}
.modal h3{font-size:0.95rem;font-weight:500;margin-top:20px;margin-bottom:6px;}
.modal p,.modal li{font-size:0.92rem;color:var(--text-secondary);line-height:1.7;margin-bottom:10px;}
.modal a{color:var(--accent);text-decoration:none;border-bottom:1px solid var(--accent-soft);}
.contact-item{display:flex;gap:14px;align-items:flex-start;padding:14px;border:1.5px solid var(--border);border-radius:var(--radius-sm);margin-bottom:10px;background:var(--surface);}
.sitemap-section{margin-bottom:20px;}
.sitemap-section h3{font-size:0.82rem;font-weight:500;color:var(--text-secondary);text-transform:uppercase;letter-spacing:.06em;margin-bottom:8px;margin-top:0;}
.sitemap-section ul{list-style:none;padding:0;}
.sitemap-section li{padding:3px 0;}
.sitemap-section a{font-size:0.92rem;color:var(--accent);} 
.sitemap-btn{background:none;border:none;border-bottom:1px solid var(--accent-soft);cursor:pointer;font-family:'DM Sans',sans-serif;font-size:0.92rem;color:var(--accent);padding:0;}
.sitemap-btn:hover{border-color:var(--accent);}
/* ── Tablet: sidebar drops below main content ── */
@media(max-width:900px){
  .layout-wrapper{grid-template-columns:1fr;gap:0;margin-top:0;padding:0 14px;}
  .sidebar{order:99;margin-top:32px;}
  .ad-right{height:250px;position:static;max-width:100%;}
  .main-content{min-width:0;}
  .card{min-width:0;max-width:100%;}
  .articles-section,.content-wrap{max-width:100%;}
}

/* ── Mobile: 480px and below ── */
@media(max-width:480px){
  /* Layout */
  .layout-wrapper{margin-top:0;padding:0 12px;}
  .calc-header{margin-bottom:20px;}

  /* Calculator card */
  .card{padding:16px 14px;border-radius:14px;}

  /* Dog/Cat toggle — keep 2 columns, but tighter */
  .toggle-group{grid-template-columns:1fr 1fr;gap:8px;margin-bottom:18px;}
  .toggle-btn{font-size:0.9rem;padding:10px 6px;min-height:44px;gap:5px;}
  .toggle-btn span.emoji{font-size:1.1rem;}

  /* Age row — stack vertically on very small screens */
  .age-row{grid-template-columns:1fr 1fr;gap:8px;}
  input[type="number"],select{font-size:16px;padding:11px 12px;min-height:44px;}

  /* Size grid — keep 3 columns, reduce padding */
  .size-grid{grid-template-columns:repeat(3,1fr);gap:6px;}
  .size-btn{padding:8px 2px;font-size:0.72rem;min-height:44px;}
  .size-btn .dog-emoji{font-size:0.95rem;margin-bottom:2px;}

  /* CTA button */
  .calc-btn{font-size:0.95rem;padding:13px 16px;min-height:48px;}

  /* Result */
  .result-number{font-size:2.4rem;}
  .result-context{font-size:0.88rem;}

  /* Ad placeholder — shrink on mobile, don't overflow */
  .ad-bottom{height:auto;min-height:60px;padding:14px;max-width:100%;}
  .ad-right{height:200px;}

  /* Articles */
  .articles-section{margin-top:36px;}
  .article-block{padding:20px 0;margin-bottom:36px;}
  .article-block h2{font-size:1.2rem;}
  .article-block h3{font-size:0.95rem;}
  .content-wrap{padding:0;margin-top:36px;}
  .content-wrap h2{margin-top:36px;font-size:1.2rem;}

  /* Tables — let them scroll, show hint */
  .table-wrap{border-radius:10px;}
  .table-wrap table{min-width:480px;}
  th{padding:8px 10px;font-size:0.68rem;}
  td{padding:7px 10px;font-size:0.8rem;}

  /* FAQ */
  summary{font-size:0.88rem;padding:12px 14px;}
  .faq-answer{font-size:0.85rem;padding:12px 14px 14px;}

  /* Footer — 4 links: 2 per row on mobile */
  .site-footer{padding:0 0 40px;}
  .footer-nav{width:100%;border-radius:10px;display:grid;grid-template-columns:1fr 1fr;}
  .footer-link{flex:none;width:100%;text-align:center;padding:11px 8px;font-size:0.8rem;border-right:none;border-bottom:1px solid var(--border);}
  .footer-link:nth-child(odd){border-right:1px solid var(--border);}
  .footer-link:nth-last-child(-n+2){border-bottom:none;}

  /* Modals — full-width on tiny screens */
  .modal{width:96vw;padding:20px 16px;max-height:88vh;}
  .modal-close{width:36px;height:36px;top:12px;right:12px;}
  .modal h2{font-size:1.2rem;}

  /* Divider */
  .divider{margin:36px auto;}

  /* Content ul lists — keep standard bullets on mobile */
  .content-wrap ul{padding-left:18px;}
  .article-block ul{padding-left:18px;}

  /* Header */
  .header-inner{padding:12px 14px;gap:10px;}
  .brand-name{font-size:1.1rem;}
}

/* ── Very small phones: 360px ── */
@media(max-width:360px){
  .age-row{grid-template-columns:1fr;}
  .size-grid{grid-template-columns:repeat(3,1fr);}
  .toggle-group{grid-template-columns:1fr 1fr;}
  .layout-wrapper{padding:0 10px;}
  .card{padding:14px 12px;}
  .result-number{font-size:2rem;}
}

/* ── Wide desktop: sidebar sticks nicely ── */
@media(min-width:901px){
  .ad-right{position:sticky;top:88px;height:600px;}
  .layout-wrapper{margin-top:0;}
}
